114→        // 2. Check user is in space
115→        boolean isInSpace = spaceQueryManager.isUserInSpace(applicantUserId, spaceId);
116→        ExceptionUtil.isTrue(isInSpace, PermissionRequestException.MEMBER_NOT_IN_SPACE);
117→
118→        // 3. Check no pending request for same document
119→        PermissionRequestEntity pending = baseMapper.selectPendingByDocumentAndApplicant(resolvedDocumentId, applicantUserId);
120→        ExceptionUtil.isNull(pending, PermissionRequestException.ALREADY_SUBMITTED_REQUEST);
