122→        // 4. Check user does not already have node permission
123→        boolean hasPermission = checkUserHasNodePermission(spaceId, applicantUserId, resolvedDocumentId);
124→        ExceptionUtil.isFalse(hasPermission, PermissionRequestException.ALREADY_HAVE_PERMISSION);
125→
126→        // 5. Debounce: short period repeated submissions only processed once
127→        String debounceKey = REDIS_DEBOUNCE_PREFIX + applicantUserId + ":" + resolvedDocumentId;
128→        Boolean firstSubmit = redisTemplate.opsForValue().setIfAbsent(debounceKey, "1", DEBOUNCE_SECONDS, TimeUnit.SECONDS);
129→        if (Boolean.FALSE.equals(firstSubmit)) {
130→            log.info("[1822-PermApply] debounce applicantUserId={} documentId={}", applicantUserId, documentId);
131→            throw new BusinessException(PermissionRequestException.ALREADY_SUBMITTED_REQUEST);
132→        }
133→
134→        // 6. Create permission request record
135→        String requestId = REQUEST_ID_PREFIX + IdUtil.getSnowflakeNextId();
136→        PermissionRequestEntity entity = PermissionRequestEntity.builder()
137→            .id(requestId)
138→            .applicantUserId(applicantUserId)
