174→        List<SpaceNodeEntity> byAppId = spaceNodeService.listByAppSpaceNodeIdsAllStatus(Collections.singletonList(nodeId));
175→        if (CollUtil.isNotEmpty(byAppId)) return byAppId.get(0);
176→        // Fallback: treat as collabspace pk if numeric (non-OnlyOffice node sent its own pk)
177→        if (nodeId.matches("^\\d+$")) {
178→            SpaceNodeEntity node = spaceNodeService.getByIdAllStatus(Long.parseLong(nodeId));
179→            ExceptionUtil.isNotNull(node, PermissionRequestException.NODE_NOT_EXIST);
