328→    @Override
329→    @Transactional(rollbackFor = Exception.class)
330→    public void submitWorkspaceJoinRequest(String workspaceId, Long applicantUserId) {
331→        ExceptionUtil.isNotNull(workspaceId, PermissionRequestException.NODE_NOT_EXIST);
332→        ExceptionUtil.isNotNull(applicantUserId, PermissionRequestException.NODE_ACCESS_DENIED);
333→
334→        // 1. Check no pending workspace request
335→        PermissionRequestEntity pending = baseMapper.selectPendingWorkspaceBySpaceAndApplicant(workspaceId, applicantUserId);
336→        ExceptionUtil.isNull(pending, PermissionRequestException.ALREADY_SUBMITTED_WORKSPACE_REQUEST);
337→
338→        // 2. Get applicant nickname and space name
339→        String applicantNickName = getApplicantNickName(applicantUserId);
340→        SpaceEntity space = spaceService.getBySpaceId(workspaceId);
341→        String spaceName = space != null && space.getName() != null ? space.getName() : workspaceId;
342→
343→        // 3. Create permission request record
344→        String requestId = REQUEST_ID_PREFIX + IdUtil.getSnowflakeNextId();
345→        PermissionRequestEntity entity = PermissionRequestEntity.builder()
346→            .id(requestId)
347→            .type(TYPE_WORKSPACE)
348→            .applicantUserId(applicantUserId)
349→            .documentId(workspaceId)
350→            .documentName(spaceName)
351→            .spaceId(workspaceId)
352→            .requestedPermissionType(null)
353→            .status(STATUS_PENDING)
354→            .isDeleted(0)
355→            .createdAt(LocalDateTime.now())
356→            .updatedAt(LocalDateTime.now())
357→            .build();
358→
359→        boolean flag = save(entity);
360→        if (!flag) {
361→            log.error("[2423-WorkspaceJoin] ERROR CREATE insert failed applicantUserId={} workspaceId={}",
362→                applicantUserId, workspaceId);
363→            throw new BusinessException(PermissionRequestException.INSERT_ERROR);
364→        }
365→        log.info("[2423-WorkspaceJoin] CREATE request requestId={} applicantUserId={} workspaceId={}",
366→            requestId, applicantUserId, workspaceId);
367→
368→        // 4. Get space admins as notification recipients
369→        List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(workspaceId);
370→        if (CollUtil.isEmpty(adminUserIds)) {
371→            log.warn("[2423-WorkspaceJoin] no admins workspaceId={}", workspaceId);
372→            return;
373→        }
374→        // Exclude applicant from recipients
375→        adminUserIds = new ArrayList<>(adminUserIds);
376→        adminUserIds.remove(applicantUserId);
377→        if (CollUtil.isEmpty(adminUserIds)) {
378→            log.warn("[2423-WorkspaceJoin] applicant is the only admin workspaceId={}", workspaceId);
379→            return;
380→        }
381→
382→        // 5. Send notification via apitable notification center
383→        notifyWorkspaceAdminsAsync(entity, spaceName, applicantNickName, adminUserIds);
384→    }
