469→    @Override
470→    @Transactional(rollbackFor = Exception.class)
471→    public void approveByRequestId(String requestId, Long notificationId, Long approverUserId) {
472→        PermissionRequestEntity request = validateAndGetRequest(requestId, approverUserId);
473→
474→        UserSimpleInfoVo approverInfo = getApproverInfo(approverUserId);
475→        String approverNickName = approverInfo != null && approverInfo.getNickName() != null ? approverInfo.getNickName() : "";
476→        String approverUuid = approverInfo != null && approverInfo.getUuid() != null ? approverInfo.getUuid() : String.valueOf(approverUserId);
477→
478→        // Get applicant unitId
479→        UnitMemberVo applicantMember = apitableGrpcClientService.findUnitMemberVo(
480→                List.of(request.getApplicantUserId()), request.getSpaceId())
481→            .stream().findFirst().orElse(null);
482→        ExceptionUtil.isNotNull(applicantMember, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);
483→        Long unitId = applicantMember.getUnitId();
484→        ExceptionUtil.isNotNull(unitId, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);
485→
486→        // Map permission type to node role
487→        String nodeRole = mapPermissionTypeToNodeRole(request.getRequestedPermissionType());
488→        log.info("[1822-PermApply] APPROVE mapRole requestId={} requestedType={} nodeRole={} unitId={} documentId={}",
489→            request.getId(), request.getRequestedPermissionType(), nodeRole, unitId, request.getDocumentId());
490→
491→        // Add node role
492→        Long spaceNodeId = parseSpaceNodeId(request.getDocumentId());
493→        if (spaceNodeId != null) {
494→            nodeRoleUpdateManager.addNodeRole(approverUserId, request.getSpaceId(), spaceNodeId, nodeRole,
495→                Collections.singletonList(unitId));
496→            log.info("[1822-PermApply] APPROVE addNodeRole ok spaceNodeId={} nodeRole={} unitId={}", spaceNodeId, nodeRole, unitId);
497→        } else {
498→            log.warn("[1822-PermApply] APPROVE WARN spaceNodeId not found for documentId={}, node permission grant SKIPPED",
499→                request.getDocumentId());
500→        }
501→
502→        // Update permission request status in collabspace
503→        int rows = baseMapper.updateStatusById(request.getId(), STATUS_APPROVED, approverUserId);
504→        log.info("[1822-PermApply] APPROVE DB updateStatus requestId={} status=APPROVED approverUserId={} rows={}",
505→            request.getId(), approverUserId, rows);
506→
507→        // Update notification extras in apitable (via gRPC) — updates shared notification record for all recipients
508→        apitableGrpcClientService.updateNotificationExtras(notificationId, STATUS_APPROVED,
509→            approverUuid, approverNickName);
510→
511→        // Mark approver's own notification as read
512→        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);
513→
514→        // Mark all other admin/manager recipients' notifications as read (same shared notificationId)
515→        markOtherRecipientNotificationsRead(notificationId, request, approverUserId);
516→
517→        // Notify applicant that their request was approved
518→        notifyApplicantResultAsync(request, STATUS_APPROVED, approverUuid, approverNickName);
519→
520→        log.info("[1822-PermApply] APPROVE done requestId={} approverUserId={} applicantUserId={} documentId={} nodeRole={}",
521→            request.getId(), approverUserId, request.getApplicantUserId(), request.getDocumentId(), nodeRole);
522→    }
