571→    /**
572→     * Validates requestId exists and approver is admin. Does NOT check PENDING status.
573→     * Used for reapprove, which can act on already-processed requests.
574→     */
575→    private void validateRequestForApprover(String requestId, Long approverUserId) {
576→        if (requestId == null || requestId.isBlank()) {
577→            ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
578→        }
579→        PermissionRequestEntity request = baseMapper.selectById(requestId);
580→        if (request == null) {
581→            log.warn("[1822-PermApply] validate requestNotFound requestId={}", requestId);
582→            ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
583→        }
584→        validateApproverIsAuthorized(approverUserId, request.getSpaceId(), request.getDocumentId());
585→    }
