587→    private PermissionRequestEntity validateAndGetRequest(String requestId, Long approverUserId) {
588→        if (requestId == null || requestId.isBlank()) {
589→            ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
590→        }
591→        PermissionRequestEntity request = baseMapper.selectById(requestId);
592→        if (request == null) {
593→            log.warn("[1822-PermApply] validate requestNotFound requestId={}", requestId);
594→            ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
595→        }
596→        if (!STATUS_PENDING.equals(request.getStatus())) {
597→            log.warn("[1822-PermApply] validate alreadyProcessed requestId={} status={}",
598→                request.getId(), request.getStatus());
599→            ExceptionUtil.isTrue(false, PermissionRequestException.REQUEST_ALREADY_PROCESSED);
600→        }
601→        validateApproverIsAuthorized(approverUserId, request.getSpaceId(), request.getDocumentId());
602→        return request;
603→    }
