605→    /**
606→     * Approver is authorized if they are a space admin (MANAGE_WORKBENCH) OR a document manager (MANAGE role on document).
607→     * Both groups receive the permission-apply notification and should be able to act on it.
608→     */
609→    private void validateApproverIsAuthorized(Long approverUserId, String spaceId, String documentId) {
610→        boolean isSpaceAdmin = spaceQueryManager.isUserSpaceAdmin(approverUserId, spaceId);
611→        if (isSpaceAdmin) {
612→            log.info("[1822-PermApply] validateApprover passed as spaceAdmin approverUserId={} spaceId={}", approverUserId, spaceId);
613→            return;
614→        }
615→        List<Long> docManagers = getDocumentManagerUserIds(documentId, spaceId);
616→        boolean isDocManager = docManagers.contains(approverUserId);
617→        log.info("[1822-PermApply] validateApprover isSpaceAdmin={} isDocManager={} approverUserId={} documentId={}",
618→            isSpaceAdmin, isDocManager, approverUserId, documentId);
619→        ExceptionUtil.isTrue(isDocManager, PermissionRequestException.INSUFFICIENT_PERMISSIONS);
620→    }
