630→    private Long parseSpaceNodeId(String documentId) {
631→        if (documentId == null) return null;
632→        // Always look up by appSpaceNodeId column first.
633→        // OnlyOffice nodes (PPT/Excel/Word) use a numeric OnlyOffice fileId as appSpaceNodeId,
634→        // which must NOT be treated as the collabspace pk.
635→        Long byAppNodeId = getSpaceNodeIdByAppNodeId(documentId);
636→        if (byAppNodeId != null) return byAppNodeId;
637→        // Fallback: if documentId is a pure numeric string, treat as spaceNodeId pk.
638→        try {
639→            return Long.parseLong(documentId);
640→        } catch (NumberFormatException e) {
641→            return null;
642→        }
643→    }
