645→    private Long getSpaceNodeIdByAppNodeId(String appNodeId) {
646→        try {
647→            List<SpaceNodeEntity> nodes = spaceNodeService.listByAppSpaceNodeIdsAllStatus(Collections.singletonList(appNodeId));
648→            if (CollUtil.isNotEmpty(nodes)) {
649→                return nodes.get(0).getId();
650→            }
651→        } catch (Exception e) {
652→            log.warn("[1822-PermApply] getSpaceNodeIdByAppNodeId failed appNodeId={}", appNodeId, e);
653→        }
654→        return null;
655→    }
