720→    /**
721→     * After one admin approves/rejects, mark all other admin and doc-manager recipients' notifications as read.
722→     * The apply notification is a shared record in apitable — the same notificationId covers all recipients,
723→     * so setNotificationRead(notificationId, otherUserId, true) marks it read for each of them individually.
724→     */
725→    private void markOtherRecipientNotificationsRead(Long notificationId, PermissionRequestEntity request,
726→                                                      Long approverUserId) {
727→        try {
728→            List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(request.getSpaceId());
729→            List<Long> docManagerUserIds = getDocumentManagerUserIds(request.getDocumentId(), request.getSpaceId());
730→
731→            Set<Long> others = new LinkedHashSet<>();
732→            others.addAll(adminUserIds);
733→            others.addAll(docManagerUserIds);
734→            others.remove(request.getApplicantUserId());
735→            others.remove(approverUserId);
736→
737→            for (Long userId : others) {
738→                apitableGrpcClientService.setNotificationRead(notificationId, userId, true);
739→            }
740→            log.info("[1822-PermApply] markOtherRecipients notificationId={} count={} requestId={}",
741→                notificationId, others.size(), request.getId());
742→        } catch (Exception e) {
743→            log.warn("[1822-PermApply] markOtherRecipients failed notificationId={} requestId={} error={}",
744→                notificationId, request.getId(), e.getMessage());
745→        }
746→    }
