784→            Map<String, Object> extras = new HashMap<>();
785→            extras.put("requestId", request.getId());
786→            extras.put("documentId", request.getDocumentId());
787→            extras.put("documentName", documentName);
788→            extras.put("status", status);
789→            extras.put("approverUserId", approverUuid);
790→            extras.put("approverNickName", approverNickName != null ? approverNickName : "");
