792→            Map<String, Object> bodyMap = new HashMap<>();
793→            bodyMap.put(BODY_EXTRAS, extras);
794→            String bodyJson = JSONUtil.toJsonStr(bodyMap);
795→
796→            apitableGrpcClientService.createNotification(
797→                templateId,
798→                approverUuid,
799→                Collections.singletonList(String.valueOf(request.getApplicantUserId())),
800→                request.getDocumentId(),
801→                request.getSpaceId(),
802→                bodyJson,
803→                false
804→            );
